-- Curso 1: Trilha Iniciante
INSERT INTO courses (title, description, difficulty, duration, `order`, is_published) VALUES
('Trilha Iniciante', 'Fundamentos de programação e ferramentas essenciais', 'beginner', 480, 1, 1);

SET @course1 = LAST_INSERT_ID();

INSERT INTO modules (courseId, title, description, `order`) VALUES
(@course1, 'Introdução à Programação', 'Conceitos básicos de lógica', 1),
(@course1, 'Git e Controle de Versão', 'Aprenda a usar Git', 2),
(@course1, 'HTML e CSS Básico', 'Crie suas primeiras páginas web', 3);

SET @mod1 = LAST_INSERT_ID() - 2;
SET @mod2 = LAST_INSERT_ID() - 1;
SET @mod3 = LAST_INSERT_ID();

INSERT INTO lessons (moduleId, title, content, duration, `order`) VALUES
(@mod1, 'O que é Programação?', '# O que é Programação?\n\nProgramação é criar instruções para computadores.', 30, 1),
(@mod1, 'Variáveis e Tipos', '# Variáveis\n\nEspaços na memória para dados.', 45, 2),
(@mod2, 'Introdução ao Git', '# Git\n\nControle de versão distribuído.', 40, 1),
(@mod3, 'Estrutura HTML', '# HTML\n\nTags fundamentais da web.', 40, 1);

